import React from 'react';
import { AlertTriangle, CheckCircle, ShieldAlert } from 'lucide-react';

const RiskProfile = ({ data }) => {
  if (!data) return null;

  const { decision_engine, malicious_score, risk_profile } = data;
  
  const getStatusColor = (code) => {
    if (code === 'BLOCK') return 'text-red-600 bg-red-100';
    if (code === 'WARN') return 'text-yellow-600 bg-yellow-100';
    return 'text-green-600 bg-green-100';
  };

  return (
    <div className="p-6 bg-white rounded-xl shadow-lg border border-gray-200">
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-xl font-bold text-gray-800">Intelligence Report</h2>
        <span className={`px-3 py-1 rounded-full text-sm font-semibold ${getStatusColor(decision_engine.action_code)}`}>
          {decision_engine.decision}
        </span>
      </div>

      <div className="mb-6">
        <p className="text-sm text-gray-500 mb-1">Overall Malicious Score</p>
        <div className="w-full bg-gray-200 rounded-full h-4">
          <div 
            className="bg-red-500 h-4 rounded-full transition-all duration-1000" 
            style={{ width: `${(malicious_score * 100).toFixed(1)}%` }}
          ></div>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        {Object.entries(risk_profile).map(([key, value]) => (
          <div key={key} className="p-3 bg-gray-50 rounded-lg border border-gray-100">
            <p className="text-xs text-gray-400 uppercase font-bold">{key}</p>
            <p className="text-lg font-mono text-gray-700">{(value * 100).toFixed(1)}%</p>
          </div>
        ))}
      </div>

      <div className="mt-6 pt-4 border-t flex items-center gap-2">
        <ShieldAlert size={18} className="text-blue-500" />
        <p className="text-sm text-gray-600">
          Uncertainty Status: <span className="font-bold">{decision_engine.uncertainty_status}</span>
        </p>
      </div>
    </div>
  );
};

export default RiskProfile;
